import{_ as i,o as n,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung031.jpg",a="/images/uebung030.jpg",s="/images/uebung032.jpg",m=JSON.parse('{"title":"Übung Lektion 20","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung20.md","filePath":"lektionen/uebung20.md"}'),d={name:"lektionen/uebung20.md"};function h(u,e,o,p,b,c){return n(),l("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-20" tabindex="-1">Übung Lektion 20 <a class="header-anchor" href="#ubung-lektion-20" aria-label="Permalink to &quot;Übung Lektion 20&quot;">​</a></h1><p>A) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>इन्द्रशत्र्वनार्या देवेन्द्रेण जीयन्ते ॥१॥ इन्द्रः शत्रुर्येषां ते ऽनार्या देवानामिन्द्रेण जीयन्ते । इन्द्रस्य शत्रव एवानार्या ... ॥ Der Götterfürst besiegt die Nichtarier, die Feinde Indras sind / deren Feind Indra ist.</p><p>शूरबलक्षत्रिययोधः शूरपुत्रमिच्छति ॥२॥ शूरस्य बलं यस्य स क्षत्रिय एव योधः शूरमेव पुत्रमि्च्छति ॥ Der Kṣatriyakrieger mit der Kraft eines Helden wünscht sich einen Heldensohn.</p><p>सुदुर्गममार्गेण स्वर्गं गम्यते । सुगमस्तु नरकमार्गः ॥३॥ सुदुर्गमेण मार्गेण स्वर्गं गम्यते । सुगमस्तु नरकस्य मार्गः ॥ Auf einem sehr beschwerlichen Weg kommt man in einen Himmel. Der Weg zu einer Hölle ist aber einfach.</p><p>मृतपुत्रब्राह्मणी रोदिति ॥४॥ मृतः पुत्रो यस्याः सा ब्राह्मणी रोदिति ॥ Die Brahmanin, deren Sohn gestorben ist, weint.</p><p>वीतमोहब्राह्मणः सम्पन्नरूपामपि शूद्रां न लुभ्यति ॥५॥ वीतो मोहो यस्य स ब्राह्मणः सम्पन्नं रूपं यस्यास्तामपि शूद्रां न लुभ्यति ॥ Ein von Verblendung freier Brahmane begehrt keine Śūdrafrau, auch sie einen vollkommenen Körper hat.</p><p>सुनीतिपुत्रः प्राप्तमतिदर्शनसाधुं गच्छति ॥६॥ शोभना नीतिर्यस्य स पुत्रः प्राप्तं मतेर्दर्शनं येन तं साधुं गच्छति ॥ Der artige Sohn geht zum Heiligen, der die Fähigkeit, Gedanken zu lesen, erworben hat.</p><p>प्राप्तप्रभावक्षत्रिया दृष्टमात्राञ्छत्रून्घ्नन्ति ॥७॥ प्राप्तः प्रभावो यैस्ते क्षत्रिया दृष्टं मात्रं येषां ताञ्छत्रून्घन्ति ॥ Die zur Macht gekommenen Kṣatriyas töten die Feinde sobald sie sie erblickt haben.</p><p>जितशत्रुयोधाः शत्रुजितान्मुञ्चन्ति ॥८॥ जितः शत्रुर्यैस्ते योधाः शत्रुणा जितान्मुञ्चन्ति । जिताः शत्रवो यैस्त्ते योधाः शत्रुभिर्जितान्मुञ्चन्ति ॥ Die Krieger, die den Feind / die Feinde besiegt hatten, befreien die vom Feind / von den Feinden Besiegten.</p><p>कृतोपनयनबालः शिवादिदेवपूजां करोति ॥९॥ कृतमुपनयनं यय्स स बालः शिव आदिर्येषां तेषां देवानां पुजां करोति ॥ Der in den Veda initiierte Knabe verehrt Śiva und die anderen Götter.</p><p>बुद्धगता दुःखादिसत्यानि शृण्वन्ति ॥१०॥ बुद्धं गता दुःखमादिर्येषां तानि सत्यानि शृण्वन्ति ॥ Die zu Buddha Gegangenen hören die Wahrheit vom Leiden und die anderen (edlen) Wahrheiten.</p><p>B) Übersetzen Sie unter Verwendung von Komposita ins Sanskrit:</p><p>1. Ein Kṣatriya, der den Stock nicht in der Hand hält, behütet das Volk nicht. अदण्डहस्तः क्षत्रियो न जनान्पाति । जनान्रक्षति ।</p><p>2. Kālidāsa und die übrigen Dichter sind die Lehrer im Sanskrit. संस्कृतगुरवः कालिदासादिक्वयः ।</p><p>3. Ein Kṣatriya hat seinen Lebensunterhalt durch Waffen. शस्त्राजीवः क्षत्रियः ।</p><p>4. Auch Śūdrafrauen haben als Dharma Gewaltlosigkeit, Wahrheit, Reinheit, Nicht-Murren, Nicht-Boshaftigkeit und Langmut. अहिंसासत्यशौचानसूयानृशंस्यक्षमाधर्माः शूद्रा अपि ॥</p><p><img src="'+t+'" alt=""><br> Abb.: शस्त्राजीवः क्षत्रियः<br> Visakhapatnam = విశాఖపట్టణం, Andhra Pradesh = ఆంధ్ర ప్రదేశ్, 18. Jhdt.<br> [Bildquelle: unforth. -- <a href="http://www.flickr.com/photos/unforth/2687570872/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/unforth/2687570872/</a>. -- Zugriff am 2008-12-23. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p><p>Lösen Sie die folgenden Komposita als Bahuvrīhi und/oder Dvandva und/oder Tatpuruṣa auf alle Ihnen als möglich erscheinenden Arten in Sanskrit auf (Ausnahme: Komposita mit adverbiellem Vorderglied). Übersetzen Sie diese verschieden aufgelösten Komposita ins Deutsche, geben Sie Geschlecht, Fall und Zahl des Gesamtkompositums an.</p><ol><li>इन्द्रशत्रवः । इन्द्रस्य शत्रवः । इन्द्रः शत्रुर्येषां ते ।</li><li>दुष्कुलायाः । दुष्टं कुलं यस्यास्तसाः ।</li><li>जातिमात्रस्य । जातेर्मात्रस्य । जातिरेव मात्रं यस्य तस्य ।</li><li>प्राप्तोदकाः । प्राप्तमुदकं यैस्ते । प्राप्तमुदकं याभिस्ताः ।</li><li>सुनीतिभिः । शोभनाभिर्नीतिभिः । शोभना नीतिर्येषां तैः । शोभना नीतिर्यासां ताभिः ।</li><li>मृतपुत्रः । मृतः पुत्रः । मृतः पुत्रो यस्य सः ।</li><li>गतपुण्येन । गतेन पुण्येन । गतं पुण्यं यस्य तेन ।</li><li>आर्यरूपम् । आर्यास्य रूपम् । आर्याणां रूपम् । आर्यं रूपम् । आर्यं रूपं यस्य तम् । तत् । आर्यानां रूपं रूपं यस्य तम् । तत् । आर्यस्य रूपं रूपं यस्य तम् । तत् ।</li><li>मुक्तासनया । मुक्तमासनं यया तया ।</li><li>तद्रूपः । तद्रूपं यस्य सः । तस्य रूपं यस्य सः ।</li><li>कृतफलानाम् । कृतस्य फलानाम् । कृतानां फलानाम् । कृतं फलं यैस्तेषाम् । कृतं फलं याभिस्तासाम् । कृतानि फलानि ... ।</li><li>व्याघ्रबलाः । व्याघ्रस्य बलं बलं येषां ते । व्याघ्रस्य बलं बलं यासां ताः ।</li><li>प्राप्तकाला । प्राप्तः कालो यया सा ।</li><li>सूरपुत्राम् । शूरः पुत्रो यस्यास्ताम् ।</li><li>कृतभिषेखः । कृतो ऽभिषेखः । कृतो ऽभिषेखो यस्य सः । कृतो ऽभिषेखो येन सः ।</li><li>शूरबलान् । शूरस्य बलं बलं येषां तान् । शूराणां ... ।</li><li>वीतमोहः । वीतो मोहः । वीतो मोहो यस्य सः ।</li><li>द्ण्डहस्तस्य । दण्दस्यैव हस्तस्य । हस्ते दण्डो यस्य तस्य ।</li><li>गतमात्रम् । गतं मात्रम् । गतं मात्रमेव यस्य तम् । तद् ।</li><li>इन्द्रपुत्रा । इन्द्रः पुत्रो यस्याः सा । Mutter des Indra (= पृथिवी )</li><li>तद्गुणाः । तस्य गुणाः । तेषां गुणाः । ते गुणाः । स गुनो येषां ते । ते गुणा येषां ते । तस्य गुणा येषां ते।  ... यासां ताः । ...</li><li>उपल्ब्धसुखैः । उपल्ब्धैः सुखैः । उपलब्धस्य सुखैः । उपलब्धानां सुखैः । उपलब्धं सुखं यैस्तैः । उपलब्धानि सुखानि यैस्तैः ।</li><li>प्राप्तप्रभावः । प्राप्तः प्रभावः । प्राप्तस्य प्रभावः । प्राप्तः प्रभावो येन सः ।</li><li>तन्मात्राणि । तस्य मात्राणि । तन्मात्रम्येषां तानि ।</li><li>प्रभूतरूपा । प्रभूतं रूपं यस्याः सा । von herausragender Gestalt</li><li>कृतोपनयनाः । कृतमुपनयनं येषां ते ।</li><li>विगतनयनम् । विगतं नयनम् । विगतं नयनं यस्य तम् । तत् । blind</li><li>बुद्धमार्गेण । बुद्धस्य मार्गेण । बुद्धस्य मार्गो मार्यो यस्य तेन । बुद्धो मार्गो यस्य तेन ।</li><li>विजयफलान् । विजयस्य फलानि येषां तान् ।</li><li>दुर्गमः । schwer zu gehen</li><li>समयकारः । समयस्य कारः । Treffen einer Abmachung, Verabredung</li><li>सम्पन्नरूपाम् । सम्पन्नं रूपं यस्यास्ताम् । deren Gestalt vollkommen ist</li><li>रूपसम्पन्नाम् । रूपेण सम्पन्नाम् । vollkommen an Gestalt</li><li>अपुण्यानाम् । Nicht-Verdienstliches । न पुण्यं येषां तेषाम् । verdienstlos</li><li>मृतगृहाणि । मृतस्य गृहाणि । मृतानां गृहाणि । Häuser des Verstorbenen ; Totenhäuser</li><li>अजनस्य । menschenleer</li><li>तद्देवतैः । सा देवता येषां तैः । ता देवता येषां तैः ।</li><li>जातपुत्राः । जाताः पुत्राः । जाताः पुत्रा येषां ते । जाताः पुत्रा यासां ताः । जातः पुत्रो ... ।</li><li>दुरन्ताभिः । übel endend, kaum endend</li><li>भूतसर्गेण । भूतानां सर्गेण । भूतस्य सर्गेण ।</li><li>मतिदर्शनम् । मतीनां दर्शनम् । Sehen der Gedanken</li><li>मुक्तहस्ता । मुक्तं हस्तं यस्याः सा । offenhändig, freigebig</li><li>तदन्तः । तस्यान्तः । सो ऽन्तः । सो ऽन्तो यस्य सः ।</li><li>जातिमात्रम् । जातेर्मात्रम् । जातिरेव मात्रं यस्य तम् । तत् । nur der Geburt (Kaste) nach ohne Erfüllung der daraus folgenden Pflichten</li><li>तज्जयेन । तस्य जयेन । तेन जयेन । स जयो यस्य तेन । तस्य जयो यस्य तेन ।</li><li>लब्धधनानाम् । लब्धानां धनानाम् । लब्धं धनं येषां तेषाम् । यासां तासाम् ।</li><li>सुदर्शः । gut zu sehen</li><li>सकारणः । mit einer Ursache । eine gemeinsame Ursache habend</li><li>तनादयः । तन् u.s.w. = 8. Präsensklasse</li><li>जातमात्राम् । जातमेव मात्रं यस्यस्ताम् । eben entstanden</li><li>दुर्जातयः । schlechte Geburten, von schlechter Geburt</li><li>हतपुत्रः । हतः पुत्रः । हतः पुत्रो यस्य सः ।</li><li>दुरासितम् । schlechte Art, zu sitzen</li><li>इष्टदेवतया । इष्टया देवतया । इष्टा देवता यस्यास्तया ।</li><li>कृतपुण्याभिः । कृतं पुण्यं याभिस्ताभिः । कृतानि पुण्यानि ... ।</li><li>श्रुत्युदितम् । श्रुतेरुदितम् । श्रुत्योदितम् ।</li><li>गतपापैः । गतैः पापैः । गतं पापं येषां तैः ।</li><li>जितारिणा । जितेनारिणा । जितो ऽरि येन तेन ।</li><li>जातकोपा । जातः कोपो यस्याः सा ।</li><li>जातिधर्मः । जातेर्धर्मः । जातीनां धर्मः ।</li><li>तत्प्रभृतयः । तस्य प्रभृतयः । सा प्रभृतिर्येषां ते । सा प्रभृतिर्यासां ताः । das u.s.w., das und das Übrige</li><li>सुदुर्जयः । sehr schwer zu besiegen, ein sehr schwerer Sieg</li><li>जितक्रोधेन । जितेने क्रोधेन । जितः क्रोधो यस्य तेन ।</li><li>दुरुपदेशम् । schwer beizubringen, schwierige Unterrichtung</li><li>लब्धलाभा । लब्धो लाभो यया सा ।</li><li>बुद्धदासः । दुद्धस्य दासः ।</li><li>मुक्तबुद्धिः । मुक्ता बुद्धिः । मुक्तस्य बुद्धिः । मुक्ता बुद्धिर्यस्य सः । मुक्ता बुद्धिर्यस्याः सा ।</li><li>यज्ञकालम् । यज्ञस्य कालम् । यज्ञस्य कालः कालो यस्य तम् । तत् ।</li><li>जितशत्रून् । जितांश्छत्रून् । जितः शत्रुर्यैस्तान् । जिताः शत्रवो यैस्तान् ।</li><li>शत्रुजितान् । शत्रुणा जितान् । शत्रुभिर्जितान् ।</li><li>तत्फलः । तत्फलं यस्य सः । तस्य फलं यस्य सः ।</li><li>सुगुणा । von guter Qualität</li><li>जातक्रोधः । जातः क्रोधः । जातः क्रोधो यस्य सः ।</li><li>दृष्टमात्रः । sobald er gesehen wurde</li><li>भूतकालः । भुतः कालः ।  Vergangenheit</li><li>सुनेत्राः । gute Augen habend, schönäugig</li><li>तदादीनाम् । तासामादीनाम् । सादिर्येषां तेषाम् । सादिर्यासां तासाम् ।</li><li>जातिस्मरणम् । जातीनां स्मरणम् । Erinnerung an frühere Geburten</li><li>सफलम् । fruchtbar</li><li>अकरुणस्य । mitleidlos</li><li>सोढदुःखाः । सोढं दुःखं यैस्ते । ... याभिस्ताः ।</li></ol><p><img src="'+a+'" alt=""><br> Abb.: सम्पन्नरूपा रूपसम्पन्ना<br> Sigiriya = සීගිරිය, Sri Lanka, 5. Jhdt<br> [Bildquelle: Dschen Reinecke / Wikipedia, GNU FDLicense]</p><p>मैत्रीकरुणामुदितोपेक्षाणां सुखदुःखपुण्यापुण्यविषयाणां भावनतश्चित्तप्रसादनम् ॥योगसूत्र १.३३॥</p><p>Die Abklärung des Geistes geschieht durch die Entfaltung von freundlichem Wohlwollen, Mitgefühl, Mitfreude und Gleichmut, die Glück und Leid, Verdienstvolles und Nicht-Verdienstvolles als Objekt haben.</p><p>तपःस्वाध्यायेश्वरप्रणिधानानि क्रियायोगः ॥योगसूत्र २.१॥<br> समाधिभावनार्थः क्लेशतनूकरणार्थश्च ॥योगसूत्र २.२॥</p><p>Yoga der Tat ist Askese, Vedastudium und aufmerksamer Dienst am HERRN.<br> Er hat als Ziel die Entfaltung der Sammlung und die Schwächung der &quot;Qualen&quot;</p><blockquote><p>Erklärung: die fünf &quot;Qualen&quot; (क्लेश) sind:</p><p>अविद्यास्मितारागद्वेषाभ्निवेशाः ॥योगसूत्र २.३॥ Unwissenheit, Ichbezogenheit, Gier, Hass und Anhänglichkeit an den Leib.</p></blockquote><p>त्रिविधदुःखात्यन्तनिवृत्तिरत्यन्तपुरुषार्थः ॥सांख्यसूत्र १.१॥ (Zum Sāṃkhyasystem siehe Basham, Wonder S. 324f.)</p><p>Das höchste Ziel des Menschen ist, dass das dreifache Leid völlig verschwindet.</p><blockquote><p>Erklärung: &quot;dreifache Leid&quot;: das aus einem selbst entsteht, das von den Objekten herrührt, das von den Göttern kommt</p></blockquote><p>Definition er Erlösung nach dem Nyāyasystem:</p><blockquote><p>बाधनालक्षणं दुःखम् ॥न्यायसूत्र १.२१॥<br> तदत्यन्तविमोक्षो ऽपवर्गः ॥न्यायसूत्र १.२२॥</p></blockquote><p>Leid ist durch Bedrängnis gekennzeichnet. Erlösung ist die völlige Befreiung davon.</p><p>Ausspruch der Materialisten nach dem सर्वदर्शनसंग्रह :</p><blockquote><p>न स्वर्गो नापवर्गो वा नैवात्मा पारलौकिकः ।<br> नैव वर्णाश्रमादीनां क्रियाश्च फलदायिकाः ॥</p></blockquote><p>Es gibt keinen Himmel, keine Erlösung, keine überweltliche Seele, es gibt auch keine fruchtbringenden Rituale und Tätigkeiten für Stände und Lebensstadien.</p><p>Ein सुभाषितम् :</p><blockquote><p>देवानां करदा विप्रा<br> विप्राणां करदा नृपाः ।<br> नृपाणां करदा लोका<br> लोकानां करदा मही ॥</p></blockquote><p>Brahmanen geben den Göttern Abgaben,<br> Den Brahmanen geben Könige Abgaben,<br> Den Königen geben die Leute Abgaben,<br> Den Leuten gibt die Erde Abgaben.</p><p>Über Besitzverhältnisse:</p><blockquote><p>भार्या पुत्रश्च दासश्च<br> त्रय एवाधनाः स्मृताः ।<br> यत्ते समधिगच्छन्ति<br> यस्य ते तस्य तद्धनम् ॥मनुस्मृति ८.४१६॥</p></blockquote><p>Gattin, Sohn und Leibeigener, diese drei sind der Überlieferung nach besitzlos. Was sie erwerben, ist besitz dessen, dem sie gehören.</p><p>Ein सुभाषितम् über weibliche Schönheit:</p><blockquote><p>तनुमध्यं पृथुश्रोणि<br> रक्तौष्ठमसितेक्षणम् ।<br> नतनाभि वपुः स्त्रीणां<br> कं न हन्त्युन्नतस्तनम् ॥</p></blockquote><p>In der Mitte schlank, an den Hüften breit, mit roten Lippen, schwarzen Augen, mit einem gebogenem Nabel und prallen Brüsten, welchen Mann erschlägt eine solch schöner Frauenkörper nicht?</p><p>Noch ein सुभाषितम् :</p><blockquote><p>सन्ति पुत्राः सुबहवो<br> दरिद्राणामनिच्छताम् ।<br> नास्ति पुत्रः समृद्धानां<br> विचित्रं विधिचेष्टितम् ॥</p></blockquote><p>Arme, die sie nicht wünschen, haben sehr viele Söhne, Reiche haben keinen einzigen Sohn. Seltsam ist der Lauf der Schöpfung.</p><p><img src="'+s+'" alt=""><br> Abb.: सन्ति पुत्राः सुबहवो दरिद्राणाम्<br> [Bildquelle: Sumanth K. Garakarajula. -- <a href="http://www.flickr.com/photos/photocracy1/2864368068/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/photocracy1/2864368068/</a>. -- Zugriff am 2008-12-23. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>Lösung zu den <a href="./uebung21">Übungen Lektion 21 - 25</a></p>',50)])])}const k=i(d,[["render",h]]);export{m as __pageData,k as default};
